function getRawSession(){try{const r=localStorage.getItem("pv_session");return r?JSON.parse(r):null;}catch(_){return null;}}
function getStoredSession(){try{const s=getRawSession();if(!s)return null;if(s.expires_at&&Date.now()/1000>s.expires_at-60)return null;return s;}catch(_){return null;}}
function storeSession(s){localStorage.setItem("pv_session",JSON.stringify(s));}
function clearSession(){localStorage.removeItem("pv_session");}
function getCurrentUserId(){try{const s=getRawSession();return s?.user?.id||null;}catch(_){return null;}}
// Access tokens expire (~1hr); refresh in place so long-lived tabs don't start
// failing writes mid-session. Safe to call repeatedly — no-ops if no session.
async function refreshSessionToken(){
  const s=getRawSession();
  if(!s?.refresh_token) return false;
  try{
    const r=await fetch(`${SUPA_URL}/auth/v1/token?grant_type=refresh_token`,{method:"POST",headers:{apikey:SUPA_KEY,"Content-Type":"application/json"},body:JSON.stringify({refresh_token:s.refresh_token})});
    const d=await r.json();
    if(r.ok&&d.access_token){storeSession(d);return true;}
  }catch(_){}
  return false;
}
function createAuthedClient(token,onAuthError){
  // Reads the access token fresh from storage on every call (instead of baking one
  // in at creation time) so the background refresh in App's mount effect actually
  // takes effect for requests made later in a long-lived session.
  // onAuthError (optional) fires the moment any request comes back 401 — i.e. the
  // session died mid-use — so the app can pop up a re-sign-in prompt immediately
  // instead of leaving stale data on screen until the user happens to navigate.
  const authH=()=>({apikey:SUPA_KEY,Authorization:`Bearer ${getRawSession()?.access_token||token}`,"Content-Type":"application/json",Prefer:"return=representation"});
  const base=`${SUPA_URL}/rest/v1`;
  const req=async(path,opts={})=>{try{const r=await fetch(`${base}${path}`,{...opts,headers:authH()});if(r.status===401&&onAuthError)onAuthError();let d=null;try{d=await r.json();}catch(_){}return{data:Array.isArray(d)?d:d?[d]:[],error:r.ok?null:d};}catch(e){return{data:[],error:{message:e.message}};}};
  const storage=createClient(SUPA_URL,SUPA_KEY).storage;
  const rpc=async(fn,params={})=>{
    try{
      const r=await fetch(`${SUPA_URL}/rest/v1/rpc/${fn}`,{method:"POST",headers:authH(),body:JSON.stringify(params)});
      if(r.status===401&&onAuthError)onAuthError();
      const d=await r.json();
      return{data:d,error:r.ok?null:d};
    }catch(e){return{data:null,error:{message:e.message}};}
  };
  // Updates the signed-in user's own auth record (e.g. user_metadata.display_name)
  // via GoTrue's /auth/v1/user endpoint, and mirrors the result into the stored
  // session so a page refresh doesn't lose it.
  const updateUser=async(payload)=>{
    try{
      const r=await fetch(`${SUPA_URL}/auth/v1/user`,{method:"PUT",headers:authH(),body:JSON.stringify(payload)});
      const d=await r.json();
      if(r.ok){ const s=getRawSession(); if(s) storeSession({...s,user:d}); }
      return{data:d,error:r.ok?null:d};
    }catch(e){return{data:null,error:{message:e.message}};}
  };
  return{from:t=>({select:(q="")=>req(`/${t}?select=*${q}`),insert:row=>req(`/${t}`,{method:"POST",body:JSON.stringify(row)}),update:(id,row)=>req(`/${t}?id=eq.${id}`,{method:"PATCH",body:JSON.stringify(row)}),delete:id=>req(`/${t}?id=eq.${id}`,{method:"DELETE"}),filter:(col,val)=>req(`/${t}?select=*&${col}=eq.${encodeURIComponent(val)}`)}),storage,rpc,updateUser};
}

// ── Design tokens: private-banking premium ────────────────────────────────────
// These are `let`, not `const` — toggleTheme() below reassigns every one of them
// in place when the user flips light/dark, and the whole render tree remounts
// (see the `key={theme}` wrapper in App()) so every component re-reads the new
// values on its very next render. Anything that hardcodes a hex color instead of
// using these tokens will NOT respond to the toggle — keep new UI on tokens.
const LIGHT_PALETTE={
  bg:"#f5f5f3", surf:"#ffffff", surf2:"#f9f9f8", surf3:"#f0efed",
  bdr:"#e9e8e5", bdr2:"#d8d6d2", txt:"#0e0e0d", mut:"#8a8883", mut2:"#5c5a57",
  acc:"#b07d3a", grn:"#2d6a4f", red:"#9b2335", amber:"#c67c1a", amb:"#8a6914",
};
const DARK_PALETTE={
  bg:"#0b0b0a", surf:"#161613", surf2:"#1e1e1a", surf3:"#272722",
  bdr:"#2c2c26", bdr2:"#3c3c34", txt:"#f5f4f0", mut:"#948f87", mut2:"#c7c3bb",
  acc:"#c99a54", grn:"#4fa17a", red:"#e5484d", amber:"#e3a748", amb:"#caa444",
};
let bg,surf,surf2,surf3,bdr,bdr2,txt,mut,mut2,acc,grn,red,amber,amb;

// Font system: Fraunces (serif, display/headings only) + Manrope (everything else — body, labels, numbers, buttons)
// Apply fontDisplay to page titles and section headers; leave all other text on Manrope.
// tabular-nums via font-variant-numeric on number elements
const fontDisplay="'Fraunces',serif";
const fontBody="'Manrope',sans-serif";

// ── Button system — one base look, three fixed sizes, three color variants ──
// Everything else in the app should compose from these instead of inventing
// its own padding/fontSize per page. None of these reference color tokens, so
// unlike inp/pbtn/gbtn/dbtn below they never need to be rebuilt on theme change.
const btnBase={display:"inline-flex",alignItems:"center",justifyContent:"center",gap:7,borderRadius:10,cursor:"pointer",fontWeight:600,letterSpacing:"-0.01em",fontFamily:"'Manrope',sans-serif",transition:"opacity 0.15s",whiteSpace:"nowrap"};
const btnSizeMd={padding:"10px 20px",fontSize:13};
const btnSizeSm={padding:"6px 12px",fontSize:12};
const btnSizeXs={padding:"3px 10px",fontSize:11};
// Bare icon button (✎ edit, × delete, etc.) — one consistent size everywhere.
// Pass color per-use (mut for neutral/edit, red for destructive).
const iconBtn={background:"none",border:"none",cursor:"pointer",padding:"4px 6px",fontSize:14,lineHeight:1,fontFamily:"'Manrope',sans-serif"};

// inp/pbtn/gbtn/dbtn (and their Sm/Xs variants) bake color-token *values* into a
// plain object at the moment they're built — a `const` here would freeze whatever
// theme was active on first module load forever, since reassigning bg/surf/txt
// afterward can't retroactively change a string already copied into an old object.
// So these are `let`, and applyTheme() rebuilds all of them fresh every toggle;
// every component still just uses them as `style={inp}` like normal.
let inp,pbtn,gbtn,dbtn,pbtnSm,gbtnSm,dbtnSm,pbtnXs,gbtnXs,dbtnXs;

function applyTheme(mode){
  const p=mode==="dark"?DARK_PALETTE:LIGHT_PALETTE;
  bg=p.bg;surf=p.surf;surf2=p.surf2;surf3=p.surf3;bdr=p.bdr;bdr2=p.bdr2;
  txt=p.txt;mut=p.mut;mut2=p.mut2;acc=p.acc;grn=p.grn;red=p.red;amber=p.amber;amb=p.amb;

  inp={width:"100%",padding:"9px 12px",background:surf,border:`1px solid ${bdr}`,borderRadius:9,color:txt,fontSize:13,fontWeight:400,outline:"none",boxSizing:"border-box",marginBottom:11,fontFamily:"'Manrope',sans-serif",letterSpacing:"-0.01em",transition:"border-color 0.15s"};
  pbtn={...btnBase,...btnSizeMd,border:`1px solid ${txt}`,background:txt,color:bg};
  gbtn={...btnBase,...btnSizeMd,border:`1px solid ${bdr}`,background:surf,color:mut2};
  dbtn={...btnBase,...btnSizeMd,border:`1px solid ${bdr}`,background:surf,color:red};
  pbtnSm={...pbtn,...btnSizeSm};
  gbtnSm={...gbtn,...btnSizeSm};
  dbtnSm={...dbtn,...btnSizeSm};
  pbtnXs={...pbtn,...btnSizeXs};
  gbtnXs={...gbtn,...btnSizeXs};
  dbtnXs={...dbtn,...btnSizeXs};
}
function getStoredTheme(){ try{return localStorage.getItem("pv_theme")==="dark"?"dark":"light";}catch(_){return "light";} }
applyTheme(getStoredTheme()); // set correct values before the very first render

// Tabular number style — apply to all financial figures
const num={fontVariantNumeric:"tabular-nums",letterSpacing:"-0.02em"};

function lbl(t){return <div style={{fontSize:10,color:mut,fontWeight:500,letterSpacing:"0.09em",textTransform:"uppercase",marginBottom:6,fontFamily:"'Manrope',sans-serif"}}>{t}</div>;}
function inrFmt(v){return"₹"+Math.round(v).toLocaleString("en-IN");}
function fmtDate(d,mode="full"){
  // mode: "full"=DD/MM/YY (transaction rows), "noYear"=DD-Mon, "monthYear"=Mon-YY
  if(!d) return "—";
  const s=d.substring(0,10);
  const p=s.split("-");
  if(p.length!==3) return s;
  const MONTHS=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  const day=parseInt(p[2],10);
  const mon=MONTHS[parseInt(p[1],10)-1]||p[1];
  const yr="'"+p[0].slice(2);
  if(mode==="noYear") return `${day}-${mon}`;
  if(mode==="monthYear") return `${mon}-${yr}`;
  return `${String(day).padStart(2,"0")}/${p[1]}/${p[0].slice(2)}`;
}

function fmtMonth(ym){
  if(!ym) return "—";
  const [y,m]=ym.split("-");
  if(!y||!m) return ym;
  const months=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  return(months[parseInt(m)-1]||m)+" '"+y.slice(2);
}
// ── CSV Download utility ────────────────────────────────────────────────────
function downloadCSV(filename, headers, rows){
  const esc=v=>{const s=String(v===null||v===undefined?'':v);return(s.includes(',')||s.includes('"')||s.includes('\n'))?'"'+s.replace(/"/g,'""')+'"':s;};
  const csv=[headers.map(esc).join(','),...rows.map(r=>r.map(esc).join(','))].join('\n');
  const blob=new Blob(['\uFEFF'+csv],{type:'text/csv;charset=utf-8'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;a.download=filename;a.click();
  setTimeout(()=>URL.revokeObjectURL(url),1000);
}

// ── PDF Print utility ────────────────────────────────────────────────────────
function printPDF({title, subtitle, period, columns, rows, totalsRow, footerNote}){
  const id="pv-print-"+Date.now();
  const colWidths=columns.map(c=>c.width||"auto").join(" ");
  const thStyle="padding:10px 14px;text-align:left;font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:0.08em;color:#6b6b6b;border-bottom:2px solid #e8e6e1;";
  const tdStyle="padding:10px 14px;font-size:12px;color:#1a1a1a;border-bottom:1px solid #f0ede8;";
  const tdRStyle="padding:10px 14px;font-size:12px;color:#1a1a1a;border-bottom:1px solid #f0ede8;text-align:right;font-variant-numeric:tabular-nums;";
  const redStyle="padding:10px 14px;font-size:12px;color:#9b2335;font-weight:600;border-bottom:1px solid #f0ede8;text-align:right;font-variant-numeric:tabular-nums;";
  const greenStyle="padding:10px 14px;font-size:12px;color:#2d6a4f;font-weight:600;border-bottom:1px solid #f0ede8;text-align:right;font-variant-numeric:tabular-nums;";

  const theadHtml=`<tr>${columns.map(c=>`<th style="${thStyle}${c.right?"text-align:right;":""}">${c.label}</th>`).join("")}</tr>`;
  const tbodyHtml=rows.map((row,ri)=>{
    const bg=ri%2===0?"#ffffff":"#faf9f7";
    return`<tr style="background:${bg}">${row.map((cell,ci)=>{
      const col=columns[ci];
      const isAmt=col?.type==="amount";
      const isNeg=isAmt&&typeof cell==="number"&&cell<0;
      const isPos=isAmt&&typeof cell==="number"&&cell>0;
      const style=isNeg?redStyle:isPos?greenStyle:col?.right?tdRStyle:tdStyle;
      const amt2=typeof cell==="number"?Math.round(cell*100)/100:cell;
      const display=isAmt&&typeof cell==="number"?(amt2>=0?"₹"+amt2.toLocaleString("en-IN",{minimumFractionDigits:2,maximumFractionDigits:2}):"−₹"+Math.abs(amt2).toLocaleString("en-IN",{minimumFractionDigits:2,maximumFractionDigits:2})):cell;
      return`<td style="${style}">${display??""}</td>`;
    }).join("")}</tr>`;
  }).join("");

  const totalsHtml=totalsRow?`<tr style="background:#f5f3ef;border-top:2px solid #e8e6e1;">
    ${totalsRow.map((cell,ci)=>{
      const col=columns[ci];
      const style=`padding:12px 14px;font-size:12px;font-weight:700;color:#1a1a1a;${col?.right?"text-align:right;":""}`;
      return`<td style="${style}">${cell??""}</td>`;
    }).join("")}</tr>`:"";

  const now=new Date();
  const generated=now.toLocaleDateString("en-IN",{day:"2-digit",month:"long",year:"numeric"})+" at "+now.toLocaleTimeString("en-IN",{hour:"2-digit",minute:"2-digit"});

  const html=`<!DOCTYPE html><html>
<head>
  <meta charset="utf-8"/>
  <title>${title}</title>
  <link href="https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&display=swap" rel="stylesheet"/>
  <style>
    *{margin:0;padding:0;box-sizing:border-box;}
    body{font-family:'Manrope',sans-serif;background:#fff;color:#1a1a1a;-webkit-print-color-adjust:exact;print-color-adjust:exact;}
    @page{margin:28mm 20mm;size:A4 portrait;}
    @media print{body{background:#fff;}}
    .page{max-width:794px;margin:0 auto;padding:0;}
    .header{padding:32px 0 24px;border-bottom:3px solid #1a1a1a;margin-bottom:24px;}
    .header-top{display:flex;justify-content:space-between;align-items:flex-start;}
    .brand{font-size:22px;font-weight:800;letter-spacing:-0.04em;color:#1a1a1a;}
    .brand span{color:#b07d3a;}
    .stmt-title{font-size:13px;font-weight:500;color:#6b6b6b;margin-top:4px;}
    .stmt-period{font-size:11px;color:#9b9590;margin-top:2px;}
    .meta-right{text-align:right;}
    .meta-label{font-size:10px;color:#9b9590;text-transform:uppercase;letter-spacing:0.08em;margin-bottom:2px;}
    .meta-value{font-size:13px;font-weight:600;color:#1a1a1a;}
    .subtitle{font-size:15px;font-weight:700;color:#1a1a1a;margin-bottom:16px;letter-spacing:-0.02em;}
    table{width:100%;border-collapse:collapse;margin-bottom:0;}
    .summary-grid{display:flex;gap:16px;margin-bottom:24px;flex-wrap:wrap;}
    .summary-card{flex:1;min-width:120px;background:#f5f3ef;border-radius:10px;padding:14px 16px;}
    .summary-label{font-size:9px;color:#9b9590;text-transform:uppercase;letter-spacing:0.08em;margin-bottom:4px;font-weight:600;}
    .summary-value{font-size:16px;font-weight:700;color:#1a1a1a;font-variant-numeric:tabular-nums;}
    .footer{margin-top:24px;padding-top:14px;border-top:1px solid #e8e6e1;display:flex;justify-content:space-between;align-items:center;}
    .footer-note{font-size:9px;color:#b0aba5;font-style:italic;}
    .footer-brand{font-size:9px;color:#b07d3a;font-weight:600;letter-spacing:0.04em;}
  </style>
</head>
<body>
  <div class="page">
    <div class="header">
      <div class="header-top">
        <div>
          <div class="brand">Points<span>Vault</span></div>
          <div class="stmt-title">${title}</div>
          ${period?`<div class="stmt-period">${period}</div>`:""}
        </div>
        <div class="meta-right">
          <div class="meta-label">Generated</div>
          <div class="meta-value">${generated}</div>
        </div>
      </div>
    </div>
    ${subtitle?`<div class="subtitle">${subtitle}</div>`:""}
    <table>
      <thead>${theadHtml}</thead>
      <tbody>${tbodyHtml}${totalsHtml}</tbody>
    </table>
    <div class="footer">
      <div class="footer-note">${footerNote||""} · ${rows.length} record${rows.length!==1?"s":""}</div>
      <div class="footer-brand">Statement generated via PointsVault</div>
    </div>
  </div>
</body></html>`;

  const w=window.open("","_blank","width=900,height=700");
  if(!w){alert("Please allow pop-ups for PointsVault to generate PDF statements.");return;}
  w.document.write(html);
  w.document.close();
  w.onload=()=>{w.focus();w.print();};
}

// ── Amex PDF Parser ──────────────────────────────────────────────────────────
async function parseAmexPDF(file){
  const MONTHS={january:"01",february:"02",march:"03",april:"04",may:"05",
    june:"06",july:"07",august:"08",september:"09",october:"10",november:"11",december:"12"};
  const TXN_DATE=/^(January|February|March|April|May|June|July|August|September|October|November|December)\s+(\d{1,2})\b/i;

  // Load PDF
  const pdfjsLib=window.pdfjsLib;
  if(!pdfjsLib) throw new Error("PDF.js not loaded — please refresh");
  const arrayBuffer=await file.arrayBuffer();
  const pdf=await pdfjsLib.getDocument({data:arrayBuffer}).promise;
  const page=await pdf.getPage(1);
  const tc=await page.getTextContent();

  // Group text items into lines by Y coordinate
  const byY={};
  tc.items.forEach(item=>{
    if(!item.str.trim()) return;
    const y=Math.round(item.transform[5]);
    const key=Object.keys(byY).find(k=>Math.abs(Number(k)-y)<=5)||String(y);
    if(!byY[key]) byY[key]=[];
    byY[key].push({t:item.str,x:Math.round(item.transform[4])});
  });

  const lines=Object.entries(byY)
    .sort((a,b)=>Number(b[0])-Number(a[0]))
    .map(([y,its])=>{
      const sorted=its.sort((a,b)=>a.x-b.x);
      return{y:Number(y),text:sorted.map(i=>i.t).join(" ")};
    });

  const fullText=lines.map(l=>l.text).join("\n");
  if(!fullText.includes("American Express")) throw new Error("Not an Amex statement");

  // DEBUG
  console.log("=== AMEX LINES ===");
  lines.slice(0,35).forEach((l,i)=>console.log("L"+i+": "+JSON.stringify(l.text)));
  console.log("TXN_DATE test:", TXN_DATE.test("February 12 PayU*CRED Mumbai 2.00"));
  lines.forEach((l,i)=>{if(TXN_DATE.test(l.text)) console.log("TXN L"+i+": "+JSON.stringify(l.text));});
  console.log("=== END ===");

  // Parse summary line: "0.00 - 2.00 + 21,002.00 = 21,000.00 1,050.00"
  let openingBal=0,newCredits=0,newDebits=0,closingBal=0,minPayment=0;
  for(const line of lines){
    if(line.text.includes(" - ")&&line.text.includes(" + ")&&line.text.includes(" = ")){
      const nums=(line.text.match(/[\d,]+\.\d{2}/g)||[]).map(n=>parseFloat(n.replace(/,/g,"")));
      if(nums.length>=4){[openingBal,newCredits,newDebits,closingBal]=nums;}
      if(nums.length>=5) minPayment=nums[4];
      break;
    }
  }

  // Parse statement period
  let stmtMonth="";
  const dateMatch=fullText.match(/(\d{2})\/(\d{2})\/(\d{4})/);
  if(dateMatch) stmtMonth=dateMatch[3]+"-"+dateMatch[2];
  const periodMatch=fullText.match(/From\s+\w+\s+\d+\s+to\s+(\w+)\s+\d+,?\s*(\d{4})/i);
  if(periodMatch){
    const mon=MONTHS[periodMatch[1].toLowerCase()]||"01";
    stmtMonth=periodMatch[2]+"-"+mon;
  }

  const stmtMon=parseInt(stmtMonth.slice(5,7)||"1");
  const stmtYr=parseInt(stmtMonth.slice(0,4)||String(new Date().getFullYear()));

  // Parse transactions
  const SKIP=["new domestic transactions","new international","other account transactions",
    "total of other","payment received","card number","foreign spending","details"];
  const transactions=[];

  for(let i=0;i<lines.length;i++){
    const line=lines[i];
    const dm=line.text.match(TXN_DATE);
    if(!dm) continue;

    const monStr=MONTHS[dm[1].toLowerCase()]||"01";
    const txnMon=parseInt(monStr);
    const txnYr=txnMon>stmtMon+1?stmtYr-1:stmtYr;
    const txnDate=txnYr+"-"+monStr+"-"+dm[2].padStart(2,"0");

    let txnText=line.text;
    let isCredit=false;

    // Check next line for CR
    if(i+1<lines.length){
      const nextTxt=lines[i+1].text.trim();
      if(nextTxt==="CR"||nextTxt.startsWith("CR ")){isCredit=true;i++;}
      else if(nextTxt.startsWith("Card Number")) i++;
    }
    if(/\bCR\s*$/.test(txnText)){isCredit=true;txnText=txnText.replace(/\bCR\s*$/,"");}

    // Extract last number as amount
    const amts=txnText.match(/[\d,]+\.\d{2}/g);
    if(!amts||!amts.length) continue;
    const amount=parseFloat(amts[amts.length-1].replace(/,/g,""));
    if(!amount) continue;

    // Description
    let desc=txnText.replace(TXN_DATE,"").replace(/[\d,]+\.\d{2}\s*$/,"").trim();
    if(SKIP.some(p=>desc.toLowerCase().includes(p))) continue;
    if(desc.length<2) continue;

    transactions.push({
      txn_date:txnDate,
      description:desc.replace(/\s+/g," ").trim(),
      amount:isCredit?-amount:amount,
      is_credit:isCredit,
      statement_month:stmtMonth,
    });
  }

  return{
    bank:"American Express",statement_month:stmtMonth,statement_date:dateMatch?dateMatch[3]+"-"+dateMatch[2]+"-"+dateMatch[1]:"",
    opening_balance:openingBal,new_credits:newCredits,new_debits:newDebits,
    closing_balance:closingBal,min_payment:minPayment,total_due:closingBal,transactions,
  };
}
// ── Download Modal component ────────────────────────────────────────────────
